program lipdecide;

{$mode objfpc}{$H+}

uses
  SysUtils, Math;

const
  PI = 3.1415926535;
  MAXPOINTS = 100;
  MAXLIC = 15;

type
  POINTRANGE = 1..100;
  LICRANGE = 1..15;
  NPOINTS = 2..100;
  NPTYPE = 3..100;
  CONNECTORS = (NOTUSED, ORR, ANDD);
  NUMQUADS = 1..3;
  COORDINATE = array[POINTRANGE] of real;
  CMATRIX = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX = array[LICRANGE, LICRANGE] of boolean;
  VECTOR = array[LICRANGE] of boolean;
  COMPTYPE = (LT, EQ, GT);

var
  X: COORDINATE;
  Y: COORDINATE;
  NUMPOINTS: NPOINTS;
  PARAMETERS: record
    LENGTH1: real;
    RADIUS1: real;
    EPSILON: real;
    AREA1: real;
    Q_PTS: NPOINTS;
    QUADS: NUMQUADS;
    DIST: real;
    N_PTS: NPTYPE;
    K_PTS: POINTRANGE;
    A_PTS: POINTRANGE;
    B_PTS: POINTRANGE;
    C_PTS: POINTRANGE;
    D_PTS: POINTRANGE;
    E_PTS: POINTRANGE;
    F_PTS: POINTRANGE;
    G_PTS: POINTRANGE;
    LENGTH2: real;
    RADIUS2: real;
    AREA2: real;
  end;
  LCM: CMATRIX;
  PUM: BMATRIX;
  CMV: VECTOR;
  FUV: VECTOR;
  LAUNCH: boolean;

  InputText: ansistring;
  InputPos: integer;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

procedure SkipWS;
begin
  while (InputPos <= Length(InputText)) and (InputText[InputPos] <= ' ') do
    Inc(InputPos);
end;

function PeekChar: char;
begin
  SkipWS;
  if InputPos <= Length(InputText) then
    PeekChar := InputText[InputPos]
  else
    PeekChar := #0;
end;

procedure ExpectChar(C: char);
begin
  SkipWS;
  if (InputPos > Length(InputText)) or (InputText[InputPos] <> C) then
    raise Exception.Create('Invalid JSON input');
  Inc(InputPos);
end;

function ParseString: ansistring;
var
  ch: char;
begin
  SkipWS;
  ExpectChar('"');
  Result := '';
  while InputPos <= Length(InputText) do
  begin
    ch := InputText[InputPos];
    Inc(InputPos);
    if ch = '"' then
      Exit;
    if ch = '\' then
    begin
      if InputPos > Length(InputText) then
        raise Exception.Create('Invalid JSON string');
      ch := InputText[InputPos];
      Inc(InputPos);
      case ch of
        '"', '\', '/' : Result := Result + ch;
        'b': Result := Result + #8;
        'f': Result := Result + #12;
        'n': Result := Result + #10;
        'r': Result := Result + #13;
        't': Result := Result + #9;
      else
        raise Exception.Create('Unsupported JSON escape');
      end;
    end
    else
      Result := Result + ch;
  end;
  raise Exception.Create('Unterminated JSON string');
end;

function ParseNumberToken: ansistring;
begin
  SkipWS;
  Result := '';
  while (InputPos <= Length(InputText)) do
  begin
    case InputText[InputPos] of
      '0'..'9', '+', '-', '.', 'e', 'E':
        begin
          Result := Result + InputText[InputPos];
          Inc(InputPos);
        end;
    else
      Break;
    end;
  end;
  if Result = '' then
    raise Exception.Create('Invalid number');
end;

function ParseReal: real;
var
  s: ansistring;
  code: integer;
begin
  s := ParseNumberToken;
  Val(s, Result, code);
  if code <> 0 then
    raise Exception.Create('Invalid real number');
end;

function ParseInt: integer;
var
  s: ansistring;
  code: integer;
begin
  s := ParseNumberToken;
  Val(s, Result, code);
  if code <> 0 then
    raise Exception.Create('Invalid integer');
end;

function ParseBool: boolean;
begin
  SkipWS;
  if Copy(InputText, InputPos, 4) = 'true' then
  begin
    Inc(InputPos, 4);
    Exit(True);
  end;
  if Copy(InputText, InputPos, 5) = 'false' then
  begin
    Inc(InputPos, 5);
    Exit(False);
  end;
  raise Exception.Create('Invalid boolean');
end;

procedure ParseRealArray(var Arr: COORDINATE; var Count: integer);
var
  i: integer;
begin
  ExpectChar('[');
  Count := 0;
  if PeekChar = ']' then
  begin
    ExpectChar(']');
    Exit;
  end;
  i := 1;
  while True do
  begin
    Arr[i] := ParseReal;
    Inc(i);
    Inc(Count);
    SkipWS;
    if PeekChar = ',' then
    begin
      ExpectChar(',');
      Continue;
    end;
    Break;
  end;
  ExpectChar(']');
end;

procedure ParseBoolArray(var Arr: VECTOR);
var
  i: integer;
begin
  ExpectChar('[');
  i := 1;
  if PeekChar = ']' then
  begin
    ExpectChar(']');
    Exit;
  end;
  while True do
  begin
    Arr[i] := ParseBool;
    Inc(i);
    SkipWS;
    if PeekChar = ',' then
    begin
      ExpectChar(',');
      Continue;
    end;
    Break;
  end;
  ExpectChar(']');
end;

procedure ParseLCMArray;
var
  i, j: integer;
  s: ansistring;
begin
  ExpectChar('[');
  for i := 1 to MAXLIC do
  begin
    ExpectChar('[');
    for j := 1 to MAXLIC do
    begin
      s := ParseString;
      if s = 'NOTUSED' then
        LCM[i, j] := NOTUSED
      else if s = 'ORR' then
        LCM[i, j] := ORR
      else if s = 'ANDD' then
        LCM[i, j] := ANDD
      else
        raise Exception.Create('Invalid LCM connector');
      if j < MAXLIC then
        ExpectChar(',');
    end;
    ExpectChar(']');
    if i < MAXLIC then
      ExpectChar(',');
  end;
  ExpectChar(']');
end;

procedure ParseParameters;
var
  key: ansistring;
begin
  ExpectChar('{');
  while True do
  begin
    key := ParseString;
    ExpectChar(':');
    if key = 'LENGTH1' then
      PARAMETERS.LENGTH1 := ParseReal
    else if key = 'RADIUS1' then
      PARAMETERS.RADIUS1 := ParseReal
    else if key = 'EPSILON' then
      PARAMETERS.EPSILON := ParseReal
    else if key = 'AREA1' then
      PARAMETERS.AREA1 := ParseReal
    else if key = 'Q_PTS' then
      PARAMETERS.Q_PTS := ParseInt
    else if key = 'QUADS' then
      PARAMETERS.QUADS := ParseInt
    else if key = 'DIST' then
      PARAMETERS.DIST := ParseReal
    else if key = 'N_PTS' then
      PARAMETERS.N_PTS := ParseInt
    else if key = 'K_PTS' then
      PARAMETERS.K_PTS := ParseInt
    else if key = 'A_PTS' then
      PARAMETERS.A_PTS := ParseInt
    else if key = 'B_PTS' then
      PARAMETERS.B_PTS := ParseInt
    else if key = 'C_PTS' then
      PARAMETERS.C_PTS := ParseInt
    else if key = 'D_PTS' then
      PARAMETERS.D_PTS := ParseInt
    else if key = 'E_PTS' then
      PARAMETERS.E_PTS := ParseInt
    else if key = 'F_PTS' then
      PARAMETERS.F_PTS := ParseInt
    else if key = 'G_PTS' then
      PARAMETERS.G_PTS := ParseInt
    else if key = 'LENGTH2' then
      PARAMETERS.LENGTH2 := ParseReal
    else if key = 'RADIUS2' then
      PARAMETERS.RADIUS2 := ParseReal
    else if key = 'AREA2' then
      PARAMETERS.AREA2 := ParseReal
    else
      raise Exception.Create('Invalid parameter key');
    SkipWS;
    if PeekChar = ',' then
    begin
      ExpectChar(',');
      Continue;
    end;
    Break;
  end;
  ExpectChar('}');
end;

procedure ParseInput;
var
  key: ansistring;
  countX, countY, i: integer;
begin
  ExpectChar('{');
  countX := 0;
  countY := 0;
  while True do
  begin
    key := ParseString;
    ExpectChar(':');
    if key = 'numpoints' then
      NUMPOINTS := ParseInt
    else if key = 'x' then
      ParseRealArray(X, countX)
    else if key = 'y' then
      ParseRealArray(Y, countY)
    else if key = 'parameters' then
      ParseParameters
    else if key = 'lcm' then
      ParseLCMArray
    else if key = 'pum_diag' then
    begin
      ExpectChar('[');
      for i := 1 to MAXLIC do
      begin
        PUM[i, i] := ParseBool;
        if i < MAXLIC then
          ExpectChar(',');
      end;
      ExpectChar(']');
    end
    else
      raise Exception.Create('Invalid input key');
    SkipWS;
    if PeekChar = ',' then
    begin
      ExpectChar(',');
      Continue;
    end;
    Break;
  end;
  ExpectChar('}');
end;

function PointEqual(I, J: integer): boolean;
begin
  PointEqual := (REALCOMPARE(X[I], X[J]) = EQ) and (REALCOMPARE(Y[I], Y[J]) = EQ);
end;

function SqDist(I, J: integer): real;
var
  dx, dy: real;
begin
  dx := X[I] - X[J];
  dy := Y[I] - Y[J];
  SqDist := dx * dx + dy * dy;
end;

function Dist(I, J: integer): real;
begin
  Dist := Sqrt(SqDist(I, J));
end;

function Quadrant(I: integer): integer;
var
  xcmp, ycmp: COMPTYPE;
begin
  xcmp := REALCOMPARE(X[I], 0.0);
  ycmp := REALCOMPARE(Y[I], 0.0);
  if (xcmp <> LT) and (ycmp <> LT) then
    Quadrant := 1
  else if (xcmp = LT) and (ycmp <> LT) then
    Quadrant := 2
  else if (xcmp <> GT) and (ycmp = LT) then
    Quadrant := 3
  else
    Quadrant := 4;
end;

function TriangleCanFitRadius(I, J, K: integer; R: real): boolean;
var
  s12, s23, s13, maxSq, sumOther: real;
  a, b, c, prod, crossAbs, rhs: real;
begin
  s12 := SqDist(I, J);
  s23 := SqDist(J, K);
  s13 := SqDist(I, K);
  maxSq := s12;
  sumOther := s23 + s13;
  if REALCOMPARE(s23, maxSq) = GT then
  begin
    maxSq := s23;
    sumOther := s12 + s13;
  end
  else if REALCOMPARE(s13, maxSq) = GT then
  begin
    maxSq := s13;
    sumOther := s12 + s23;
  end;

  if REALCOMPARE(maxSq, 4.0 * R * R) = GT then
  begin
    TriangleCanFitRadius := False;
    Exit;
  end;

  if REALCOMPARE(maxSq, sumOther) <> LT then
  begin
    TriangleCanFitRadius := True;
    Exit;
  end;

  a := Sqrt(s12);
  b := Sqrt(s23);
  c := Sqrt(s13);
  prod := a * b * c;
  crossAbs := Abs((X[J] - X[I]) * (Y[K] - Y[I]) - (Y[J] - Y[I]) * (X[K] - X[I]));
  rhs := 2.0 * crossAbs * R;
  TriangleCanFitRadius := REALCOMPARE(prod, rhs) <> GT;
end;

function AngleCondition(I, J, K: integer; Eps: real): boolean;
var
  ux, uy, vx, vy, dot, lenU, lenV, threshold: real;
begin
  if PointEqual(I, J) or PointEqual(K, J) then
  begin
    AngleCondition := False;
    Exit;
  end;

  ux := X[I] - X[J];
  uy := Y[I] - Y[J];
  vx := X[K] - X[J];
  vy := Y[K] - Y[J];
  lenU := Sqrt(ux * ux + uy * uy);
  lenV := Sqrt(vx * vx + vy * vy);
  if (REALCOMPARE(lenU, 0.0) = EQ) or (REALCOMPARE(lenV, 0.0) = EQ) then
  begin
    AngleCondition := False;
    Exit;
  end;

  dot := ux * vx + uy * vy;
  threshold := -Cos(Eps) * lenU * lenV;
  AngleCondition := REALCOMPARE(dot, threshold) = GT;
end;

procedure DecideLICs;
var
  i, j, k, q, count, quadCount: integer;
  seen: array[1..4] of boolean;
  foundGreater, foundLess: boolean;
  d: real;
begin
  for i := 1 to MAXLIC do
    CMV[i] := False;

  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(Dist(i, i + 1), PARAMETERS.LENGTH1) = GT then
    begin
      CMV[1] := True;
      Break;
    end;

  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
      if not TriangleCanFitRadius(i, i + 1, i + 2, PARAMETERS.RADIUS1) then
      begin
        CMV[2] := True;
        Break;
      end;
  end;

  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
      if AngleCondition(i, i + 1, i + 2, PARAMETERS.EPSILON) then
      begin
        CMV[3] := True;
        Break;
      end;
  end;

  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
      if REALCOMPARE(Abs((X[i + 1] - X[i]) * (Y[i + 2] - Y[i]) - (Y[i + 1] - Y[i]) * (X[i + 2] - X[i])), 2.0 * PARAMETERS.AREA1) = GT then
      begin
        CMV[4] := True;
        Break;
      end;
  end;

  if NUMPOINTS >= PARAMETERS.Q_PTS then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
    begin
      FillChar(seen, SizeOf(seen), 0);
      quadCount := 0;
      for j := i to i + PARAMETERS.Q_PTS - 1 do
      begin
        q := Quadrant(j);
        if not seen[q] then
        begin
          seen[q] := True;
          Inc(quadCount);
        end;
      end;
      if quadCount > PARAMETERS.QUADS then
      begin
        CMV[5] := True;
        Break;
      end;
    end;
  end;

  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[i + 1], X[i]) = LT then
    begin
      CMV[6] := True;
      Break;
    end;

  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      j := i + PARAMETERS.N_PTS - 1;
      if PointEqual(i, j) then
      begin
        for k := i + 1 to j - 1 do
          if REALCOMPARE(Dist(i, k), PARAMETERS.DIST) = GT then
          begin
            CMV[7] := True;
            Break;
          end;
      end
      else
      begin
        d := Dist(i, j);
        for k := i + 1 to j - 1 do
          if REALCOMPARE(Abs((X[j] - X[i]) * (Y[k] - Y[i]) - (Y[j] - Y[i]) * (X[k] - X[i])), PARAMETERS.DIST * d) = GT then
          begin
            CMV[7] := True;
            Break;
          end;
      end;
      if CMV[7] then
        Break;
    end;
  end;

  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
      if REALCOMPARE(Dist(i, i + PARAMETERS.K_PTS + 1), PARAMETERS.LENGTH1) = GT then
      begin
        CMV[8] := True;
        Break;
      end;
  end;

  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
      if not TriangleCanFitRadius(i, i + PARAMETERS.A_PTS + 1, i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2, PARAMETERS.RADIUS1) then
      begin
        CMV[9] := True;
        Break;
      end;
  end;

  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
      if AngleCondition(i, i + PARAMETERS.C_PTS + 1, i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2, PARAMETERS.EPSILON) then
      begin
        CMV[10] := True;
        Break;
      end;
  end;

  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
      for j := i + PARAMETERS.E_PTS + 1 to NUMPOINTS - PARAMETERS.F_PTS do
        for k := j + PARAMETERS.F_PTS + 1 to NUMPOINTS do
          if REALCOMPARE(Abs((X[j] - X[i]) * (Y[k] - Y[i]) - (Y[j] - Y[i]) * (X[k] - X[i])), 2.0 * PARAMETERS.AREA1) = GT then
          begin
            CMV[11] := True;
            Break;
          end;
    if CMV[11] then ;
  end;

  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
      if REALCOMPARE(X[i + PARAMETERS.G_PTS + 1], X[i]) = LT then
      begin
        CMV[12] := True;
        Break;
      end;
  end;

  if NUMPOINTS >= 3 then
  begin
    foundGreater := False;
    foundLess := False;
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      d := Dist(i, i + PARAMETERS.K_PTS + 1);
      if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
        foundGreater := True;
      if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then
        foundLess := True;
      if foundGreater and foundLess then
        Break;
    end;
    CMV[13] := foundGreater and foundLess;
  end;

  if NUMPOINTS >= 5 then
  begin
    foundGreater := False;
    foundLess := False;
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 1 do
    begin
      if not TriangleCanFitRadius(i, i + PARAMETERS.A_PTS + 1, i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2, PARAMETERS.RADIUS1) then
        foundGreater := True;
      if TriangleCanFitRadius(i, i + PARAMETERS.A_PTS + 1, i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2, PARAMETERS.RADIUS2) then
        foundLess := True;
      if foundGreater and foundLess then
        Break;
    end;
    CMV[14] := foundGreater and foundLess;
  end;

  if NUMPOINTS >= 5 then
  begin
    foundGreater := False;
    foundLess := False;
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 1 do
    begin
      for j := i + PARAMETERS.E_PTS + 1 to NUMPOINTS - PARAMETERS.F_PTS do
        for k := j + PARAMETERS.F_PTS + 1 to NUMPOINTS do
        begin
          if REALCOMPARE(Abs((X[j] - X[i]) * (Y[k] - Y[i]) - (Y[j] - Y[i]) * (X[k] - X[i])), 2.0 * PARAMETERS.AREA1) = GT then
            foundGreater := True;
          if REALCOMPARE(Abs((X[j] - X[i]) * (Y[k] - Y[i]) - (Y[j] - Y[i]) * (X[k] - X[i])), 2.0 * PARAMETERS.AREA2) = LT then
            foundLess := True;
          if foundGreater and foundLess then
            Break;
        end;
      if foundGreater and foundLess then
        Break;
    end;
    CMV[15] := foundGreater and foundLess;
  end;
end;

procedure BuildPUMAndFUV;
var
  i, j: integer;
begin
  for i := 1 to MAXLIC do
  begin
    for j := 1 to MAXLIC do
    begin
      if i = j then
        Continue;
      case LCM[i, j] of
        NOTUSED: PUM[i, j] := True;
        ORR: PUM[i, j] := CMV[i] or CMV[j];
        ANDD: PUM[i, j] := CMV[i] and CMV[j];
      end;
    end;
  end;

  for i := 1 to MAXLIC do
  begin
    if not PUM[i, i] then
      FUV[i] := True
    else
    begin
      FUV[i] := True;
      for j := 1 to MAXLIC do
        if not PUM[i, j] then
        begin
          FUV[i] := False;
          Break;
        end;
    end;
  end;

  LAUNCH := True;
  for i := 1 to MAXLIC do
    if not FUV[i] then
    begin
      LAUNCH := False;
      Break;
    end;
end;

procedure Decide;
var
  i, j: integer;
begin
  DecideLICs;
  for i := 1 to MAXLIC do
    PUM[i, i] := PUM[i, i];
  BuildPUMAndFUV;
end;

procedure WriteBool(B: boolean);
begin
  if B then
    Write('true')
  else
    Write('false');
end;

procedure WriteBoolArray(const V: VECTOR);
var
  i: integer;
begin
  Write('[');
  for i := 1 to MAXLIC do
  begin
    if i > 1 then
      Write(',');
    WriteBool(V[i]);
  end;
  Write(']');
end;

procedure WritePUM;
var
  i, j: integer;
begin
  Write('[');
  for i := 1 to MAXLIC do
  begin
    if i > 1 then
      Write(',');
    Write('[');
    for j := 1 to MAXLIC do
    begin
      if j > 1 then
        Write(',');
      WriteBool(PUM[i, j]);
    end;
    Write(']');
  end;
  Write(']');
end;

procedure EmitOutput;
begin
  Write('{"cmv":');
  WriteBoolArray(CMV);
  Write(',"pum":');
  WritePUM;
  Write(',"fuv":');
  WriteBoolArray(FUV);
  Write(',"launch":');
  WriteBool(LAUNCH);
  Write('}');
end;

procedure ReadAllInput;
var
  line: ansistring;
begin
  InputText := '';
  while not EOF do
  begin
    ReadLn(line);
    InputText := InputText + line;
    if not EOF then
      InputText := InputText + LineEnding;
  end;
  InputPos := 1;
end;

begin
  ReadAllInput;
  ParseInput;
  Decide;
  EmitOutput;
end.
